+    return {
+      averageRSS: memoryUsages.reduce((sum, usage) => sum + usage, 0) / memoryUsages.length,
+      peakRSS: Math.max(...memoryUsages),
+      averageHeap: heapUsages.reduce((sum, usage) => sum + usage, 0) / heapUsages.length,
+      peakHeap: Math.max(...heapUsages),
