+    // Throughput bottlenecks
+    for (const [scenario, result] of results) {
+      if (result.throughput && result.throughput.optimalThroughput < result.throughput.maxThroughput * 0.8) {
+        bottlenecks.push({
+          type: 'THROUGHPUT_DEGRADATION',
+          scenario: scenario,
